using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed from "Discriminator" to "$type" in EF Core 9.
            // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
            // Preserve the old property name so existing documents remain readable without migration.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Id format changed from "EntityType|<key>" to just "<key>" in EF Core 9.
            // Existing documents have id values like "Product|123".
            // Map the explicit CosmosId property to the JSON "id" field to match the old format.
            entity.HasKey(p => p.CosmosId);
            entity.Property(p => p.CosmosId)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            entity.Property(p => p.Id).ToJsonProperty("Id");

            // BREAKING CHANGE 3 — HasIndex() on Cosmos now throws instead of being silently ignored.
            // Removed: entity.HasIndex(p => p.Sku);
            // Cosmos DB manages indexes server-side via indexing policy, not EF model config.
        });
    }
}

/// <summary>
/// Generates id values in the EF Core 8 format: "EntityTypeName|KeyValue".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    protected override string NextValue(EntityEntry entry)
    {
        var entityType = entry.Metadata.ShortName();
        var id = entry.Property("Id").CurrentValue;
        return $"{entityType}|{id}";
    }
}

